import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { Cpu, Terminal, Lock, ShieldCheck } from 'lucide-react';
import toast from 'react-hot-toast';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  // We trigger useTheme to ensure CSS variables are injected into the DOM
  useTheme(); 
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('FIELDS_REQUIRED');
    
    const toastId = toast.loading('INITIALIZING_SECURE_HANDSHAKE...');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('ACCESS_GRANTED', { id: toastId });
      navigate('/dashboard'); 
    } catch (err) { 
      toast.error('GATE_REJECTION: INVALID_CREDENTIALS', { id: toastId }); 
    } finally { 
      setLoading(false); 
    }
  };

  const styles = {
    container: { 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      padding: '2rem',
      backgroundColor: 'var(--bg-main, #050505)',
      position: 'relative'
    },
    card: { 
      width: '100%', 
      maxWidth: '420px', 
      padding: '3rem', 
      backgroundColor: 'var(--surface-glass, #141414)', 
      borderRadius: '24px', 
      border: '1px solid var(--surface-border, rgba(255,255,255,0.1))', 
      boxShadow: 'var(--shadow-elevated, 0 20px 50px rgba(0,0,0,0.5))',
      position: 'relative',
      overflow: 'hidden',
      backdropFilter: 'blur(18px)'
    },
    headerIcon: {
      display: 'flex',
      justifyContent: 'center',
      marginBottom: '1rem',
      color: 'var(--accent-primary, #9d5ae5)'
    },
    title: { 
      fontSize: '1.8rem', 
      color: 'var(--text-primary, #fff)', 
      marginBottom: '0.5rem', 
      textAlign: 'center',
      textTransform: 'uppercase',
      letterSpacing: '0.3em',
      fontWeight: '300'
    },
    subtitle: {
      textAlign: 'center',
      fontSize: '10px',
      color: 'var(--text-muted, rgba(255,255,255,0.4))',
      textTransform: 'uppercase',
      letterSpacing: '0.25em',
      marginBottom: '2.5rem'
    },
    inputGroup: { 
      position: 'relative', 
      marginBottom: '1.5rem', 
      width: '100%',
      display: 'flex',
      flexDirection: 'column'
    },
    label: {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      fontSize: '10px',
      color: 'var(--accent-primary, #9d5ae5)',
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.15em',
      marginBottom: '8px',
      paddingLeft: '4px'
    },
    input: { 
      width: '100%', 
      padding: '1rem', 
      paddingRight: '3.5rem',
      backgroundColor: 'var(--input-bg, rgba(255,255,255,0.05))', 
      border: '1px solid var(--input-border, rgba(255,255,255,0.1))', 
      borderRadius: '12px', 
      color: 'var(--text-primary, #fff)', 
      fontSize: '14px', 
      outline: 'none',
      transition: 'all 0.3s ease',
    },
    toggleBtn: { 
      position: 'absolute', 
      right: '15px', 
      bottom: '12px', 
      background: 'none', 
      border: 'none', 
      color: 'var(--text-muted, rgba(255,255,255,0.3))', 
      cursor: 'pointer', 
      fontSize: '1.2rem',
      zIndex: 10,
      display: 'flex',
      alignItems: 'center'
    },
    button: { 
      width: '100%', 
      padding: '1.1rem', 
      marginTop: '1rem', 
      background: 'linear-gradient(135deg, var(--accent-secondary, #7a3cc2), var(--accent-primary, #9d5ae5))', 
      color: '#fff', 
      border: 'none', 
      borderRadius: '12px', 
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.2em',
      fontSize: '11px',
      cursor: 'pointer', 
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '12px',
      transition: 'all 0.3s ease',
      boxShadow: '0 0 15px var(--accent-glow)'
    },
  };

  return (
    <div style={styles.container}>
      <div style={styles.card} className="reveal-data">
        {/* Active Laser Scan Decor */}
        <div className="animate-scan" />
        
        <div style={styles.headerIcon}>
          <Cpu size={42} className="animate-pulse" />
        </div>

        <h2 style={styles.title}>Access_Gate</h2>
        <p style={styles.subtitle}>Node_ID: 8000 // Security_Protocol</p>

        <form onSubmit={handleLogin}>
          <div style={styles.inputGroup}>
            <label style={styles.label} htmlFor="email">
              <Terminal size={12} /> Operator_Email
            </label>
            <input 
              id="email"
              type="email" 
              placeholder="operator@finify.ai" 
              value={email} 
              onChange={(e) => setEmail(e.target.value)} 
              style={styles.input} 
              className="cyber-input-focus"
              required
            />
          </div>
          
          <div style={styles.inputGroup}>
            <label style={styles.label} htmlFor="password">
              <Lock size={12} /> Secure_Key
            </label>
            <input 
              id="password"
              type={showPass ? "text" : "password"} 
              placeholder="••••••••" 
              value={password} 
              onChange={(e) => setPassword(e.target.value)} 
              style={styles.input} 
              className="cyber-input-focus"
              required
            />
            <button 
              type="button" 
              onClick={() => setShowPass(!showPass)} 
              style={styles.toggleBtn}
              tabIndex="-1"
            >
              {showPass ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
          
          <button 
            type="submit" 
            style={styles.button} 
            disabled={loading} 
            className="hover:brightness-110 active:scale-95"
          >
            {loading ? 'SYNCHRONIZING...' : <><ShieldCheck size={16}/> Connect_to_Terminal</>}
          </button>
        </form>

        <div style={{
          textAlign: 'center', 
          marginTop: '2.5rem', 
          paddingTop: '1.5rem', 
          borderTop: '1px solid var(--surface-border, rgba(255,255,255,0.05))'
        }}>
          <Link to="/register" style={{
            color: 'var(--accent-primary, #9d5ae5)', 
            fontSize: '10px', 
            textTransform: 'uppercase', 
            letterSpacing: '0.15em',
            textDecoration: 'none'
          }}>
            Initialize_New_Identity
          </Link>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
